from flask import Flask, request, jsonify
from pysaml2 import binding as bindings
from pysaml2 import config, mathutils, xmlsecureutil
from pysaml2.saml2.authnrequest import AuthnRequest
import requests

app = Flask(__name__)
config.parse_file(r'path/to/your/pysaml2-sp.xml')
sp = bindings.ServiceProvider(id='your-entity-id')

@app.route('/sso', methods=['GET'])
def sso():
    assert request.args.get('destUrl') and request.args.get('userInfo'), "Missing required parameters"

    dest_url = request.args.get('destUrl')
    user_info = request.args.get('userInfo')

    authn_request = AuthnRequest(
        destination=dest_url,
        id=mathutils.make_id(),
        issuer=sp.entityid,
        protocol_binding='urn:oasis:names:tc:SAML2:bindings:HTTP-POST',
        audience=dest_url.split('?')[0].replace('/sso', ''),
    )

    assert authn_request.sign(sp, user_info)

    response = {
        'assertion': authn_request.to_string(
            bindings.outputformat.XML_V11,
            canonical=True,
            sign=False,
        ),
        'serviceProviderEntityID': sp.entityid,
    }

    return jsonify(response)

if __name__ == "__main__":
    app.run()